class Solution:
    def calculate(self, s: str) -> int:
        s = s.replace(" ", "")
        num = 0
        stack = []
        sign = 1
        operator = '+'
        for i in range(len(s)):
            if s[i].isdigit():
                num = num * 10 + int(s[i])
            if s[i] in '+-*/' or i == len(s) - 1:
                if operator == '+':
                    stack.append(num * sign)
                elif operator == '-':
                    stack.append(-num * sign)
                elif operator == '*':
                    stack.append(stack.pop() * (num * sign))
                else:
                    stack.append(int(stack.pop() / (num * sign)))
                operator = s[i]
                num = 0
                sign = 1
            if s[i] == '-':
                sign *= -1
        return sum(stack)
